export interface Condition {
  name: string;
  slug: string;
  icd10: string;
  description: string;
  severity: "Mild" | "Moderate" | "Severe" | "Critical";
}

export interface MedicalDepartment {
  id: string;
  name: string;
  slug: string;
  icon: string;
  color: string;
  description: string;
  conditions: Condition[];
}

function toSlug(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function cond(name: string, icd10: string, description: string, severity: Condition["severity"]): Condition {
  return { name, slug: toSlug(name), icd10, description, severity };
}

