export function getDepartmentBySlug(slug: string): MedicalDepartment | undefined {
  return medicalDepartments.find(d => d.slug === slug);
}

export function getConditionBySlug(deptSlug: string, condSlug: string): { dept: MedicalDepartment; condition: Condition } | undefined {
  const dept = getDepartmentBySlug(deptSlug);
  if (!dept) return undefined;
  const condition = dept.conditions.find(c => c.slug === condSlug);
  if (!condition) return undefined;
  return { dept, condition };
}

export const totalConditions = medicalDepartments.reduce((sum, d) => sum + d.conditions.length, 0);
